<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Mini Desktop</title>
<style>
  *{box-sizing:border-box;margin:0;padding:0;}
  body,html{height:100%;font-family:sans-serif;background:#222;color:#eee;}
  #desktop{position:absolute;top:0;left:0;width:100%;height:100%;background:url('');}
  #taskbar{
    position:absolute;bottom:0;left:0;width:100%;height:40px;
    background:#111;border-top:1px solid #444;display:flex;align-items:center;padding-left:10px;}
  .launcher{width:32px;height:32px;margin-right:8px;background:#333;border-radius:4px;cursor:pointer;display:flex;align-items:center;justify-content:center;}
  .launcher:hover{background:#555;}
  #open-files::before{content:"📁";}
  #open-notepad::before{content:"📝";}
  .window{
    position:absolute;top:50px;left:50px;width:400px;height:300px;background:#333;border-radius:4px;
    box-shadow:0 2px 10px rgba(0,0,0,.5);display:none;}
  .win-header{height:30px;background:#222;color:#ddd;font-weight:bold;padding-left:8px;display:flex;align-items:center;justify-content:space-between;cursor:pointer;}
  .win-close{width:20px;height:20px;text-align:center;border-radius:50%;background:#555;margin-right:4px;cursor:pointer;}
  .win-close:hover{background:#777;}
  .win-body{padding:8px;overflow:auto;background:#444;color:#eee;}
  #files-window{width:500px;height:400px;}
  #notepad-window{width:600px;height:450px;}
  /* Files app */
  #files-path{margin-bottom:4px;font-size:0.9em;}
  .fs-item{padding:2px 4px;margin:1px 0;cursor:pointer;}
  .fs-item:hover{background:#555;}
  /* Notepad app */
  #tabs{display:flex;border-bottom:1px solid #555;background:#222;}
  .tab{
    padding:6px 12px;margin-right:2px;background:#333;color:#ddd;cursor:pointer;
    border-top-left-radius:4px;border-top-right-radius:4px;}
  .tab.active{background:#444;color:white;}
  #new-tab{padding:6px 12px;background:#333;color:#ddd;cursor:pointer;border:none;}
  #editor{width:100%;height:calc(100% - 30px);border:none;padding:8px;background:#222;color:#eee;font-family:monospace;}
</style>
</head>
<body>
<div id="desktop">
  <div id="taskbar">
    <div id="open-files" class="launcher"></div>
    <div id="open-notepad" class="launcher"></div>
  </div>

  <!-- Files Window -->
  <div id="files-window" class="window">
    <div class="win-header">Files<span class="win-close">&times;</span></div>
    <div class="win-body">
      <div id="files-path">/</div>
      <button id="files-up">Up</button>
      <div id="file-list"></div>
    </div>
  </div>

  <!-- Notepad Window -->
  <div id="notepad-window" class="window">
    <div class="win-header">Notepad<span class="win-close">&times;</span></div>
    <div class="win-body">
      <div id="tabs"></div>
      <textarea id="editor"></textarea>
    </div>
  </div>
</div>

<script>
/* ---------- Utility ---------- */
function $(id){return document.getElementById(id);}
function show(el){el.style.display='block';}
function hide(el){el.style.display='none';}

/* ---------- Files App ---------- */
const fs = {
  '/': {bin:{}, etc:{}, home:{user:{Documents:{}, Downloads:{}, Pictures:{}}}, usr:{}, var:{}},
};
let currentPath = '/';

function renderFiles(){
  const list=$('file-list');
  list.innerHTML='';
  const parts=currentPath.split('/').filter(Boolean);
  let node=fs['/'];
  for(const p of parts){node=node[p];}
  for(const name in node){
    const item=document.createElement('div');
    item.className='fs-item';
    item.textContent=name;
    if(typeof node[name]==='object'){
      item.dataset.type='folder';
      item.addEventListener('dblclick',()=>{navigate(name);});
    }else{
      item.dataset.type='file';
    }
    list.appendChild(item);
  }
}
function navigate(folder){
  currentPath+=folder+'/';
  $('files-path').textContent=currentPath;
  renderFiles();
}
$('files-up').addEventListener('click',()=>{
  if(currentPath!=='/'){
    const parts=currentPath.split('/').filter(Boolean);
    parts.pop();
    currentPath='/' + parts.join('/') + (parts.length?'/':'');
    $('files-path').textContent=currentPath;
    renderFiles();
  }
});
renderFiles();

/* ---------- Notepad App ---------- */
const STORAGE_KEY='notepadTabs';
let tabs=[];
let activeTabIndex=0;

function loadTabs(){
  const data=localStorage.getItem(STORAGE_KEY);
  if(data)tabs=JSON.parse(data); else tabs=[{id:Date.now(),content:''}];
}
function saveTabs(){localStorage.setItem(STORAGE_KEY,JSON.stringify(tabs));}

function renderTabs(){
  const tabBar=$('tabs');
  tabBar.innerHTML='';
  tabs.forEach((t,i)=>{
    const tdiv=document.createElement('div');
    tdiv.className='tab'+(i===activeTabIndex?' active':'');
    tdiv.textContent='Untitled';
    tdiv.dataset.index=i;
    tdiv.addEventListener('click',()=>{switchTab(i);});
    tabBar.appendChild(tdiv);
  });
  const newBtn=document.createElement('button');
  newBtn.id='new-tab';newBtn.textContent='+';
  newBtn.addEventListener('click',addNewTab);
  tabBar.appendChild(newBtn);
}
function switchTab(idx){
  activeTabIndex=idx;
  $('editor').value=tabs[idx].content;
  renderTabs();
}
function addNewTab(){
  tabs.push({id:Date.now(),content:''});
  activeTabIndex=tabs.length-1;
  renderTabs();
  $('editor').focus();
}
$('editor').addEventListener('input',()=>{
  tabs[activeTabIndex].content=$('editor').value;
  saveTabs();
});

loadTabs();renderTabs();switchTab(activeTabIndex);

/* ---------- Window Show/Hide ---------- */
function toggleWindow(id){
  const win=$(id);
  if(win.style.display==='block')hide(win);else show(win);
}
$('open-files').addEventListener('click',()=>toggleWindow('files-window'));
$('open-notepad').addEventListener('click',()=>toggleWindow('notepad-window'));
document.querySelectorAll('.win-close').forEach(btn=>{
  btn.addEventListener('click',(e)=>{hide(e.target.parentElement.parentElement);});
});

/* ---------- Make windows draggable (optional) ---------- */
function makeDraggable(win){
  const header=win.querySelector('.win-header');
  let offsetX,offsetY;
  header.onmousedown=function(e){
    offsetX=e.clientX-win.offsetLeft;
    offsetY=e.clientY-win.offsetTop;
    document.onmousemove=move;
    document.onmouseup=stop;
  };
  function move(e){win.style.left=(e.clientX-offsetX)+'px';win.style.top=(e.clientY-offsetY)+'px';}
  function stop(){document.onmousemove=null;document.onmouseup=null;}
}
makeDraggable($('files-window'));
makeDraggable($('notepad-window'));

</script>
</body>
</html>
